from utils.operations import sumar, restar

def calcular(operacion, a, b):
    try:
        if operacion == 'sumar':
            return sumar(a, b)
        elif operacion == 'restar':
            return restar(a, b)
        else:
            raise ValueError("Operación desconocida")
    except ValueError as e:
        return f"Error: {e}"

if __name__ == '__main__':
